-    max_fp32 = fmaxf(max_fp32, data_fp32[ii][0]);
-    max_fp32 = fmaxf(max_fp32, data_fp32[ii][1]);
-  }
-
-// Compute inside the warp.
-#pragma unroll
-  for (int xor_mask = THREADS_PER_WARP / 2; xor_mask > 0; xor_mask /= 2) {
