-  }
-#endif
-
-  // // DEBUG.
-  // if( blockIdx.z == 1 && threadIdx.y == 0 && threadIdx.x == 5 ) {
-  //   printf("elt=%12.8f sum_fp32=%12.8f\n", data_fp32[0][0], sum_fp32);
-  // }
-
-  // Fix the sum if needed.
-  if (sum_fp32 == 0.f || sum_fp32 != sum_fp32) {
